requirements.capl_script:
/* REQ: BCM-REQ-01 */
variables
{
  message 300 BCBCM_Body_State bcmMsg;
  int hazardState = 0;
}
on key 'h'
{
  // Reset payload before setting signals
  int i;
  for (i = 0; i < 8; i++)
  {
    bcmMsg.byte(i) = 0;
  }
  bcmMsg.dlc = 8;
  hazardState = !hazardState;
  bcmMsg.Bdy_Hazard_Active = hazardState;
  output(bcmMsg);
}

/* REQ: BCM-REQ-02 */
variables
{
  message 300 BCBCM_Body_State bcmMsg;
