/* REQ: BCM-REQ-03 */
variables
{
  message 300 bcmMsg;
  int fl = 0; int fr = 0; int rl = 0; int rr = 0;
}
void sendDoorStatus()
{
  // Reset payload before setting signals
  int i;
  for (i = 0; i < 8; i++)
  {
    bcmMsg.byte(i) = 0;
  }
  bcmMsg.dlc = 8;
  bcmMsg.Bdy_Door_Front_Left = fl;
  bcmMsg.Bdy_Door_Front_Right = fr;
  bcmMsg.Bdy_Door_Rear_Left = rl;
  bcmMsg.Bdy_Door_Rear_Right = rr;
  output(bcmMsg);
}
on key '1' { fl = !fl; sendDoorStatus(); }
on key '2' { fr = !fr; sendDoorStatus(); }
on key '3' { rl = !rl; sendDoorStatus(); }
on key '4' { rr = !rr; sendDoorStatus(); }

