/* REQ: ECM-REQ-01 */
variables
{
  msTimer speedTimer;
  float flSpeed = 0.0;
  float frSpeed = 0.0;
  float rlSpeed = 0.0;
  float rrSpeed = 0.0;
  float vehicleSpeed = 0.0;
  message ECM_Powertrain_Data msgECM;
}
on start
{
  // Initialize message payload to safe state
  int i;
  for (i = 0; i < 8; i++)
  {
    msgECM.byte(i) = 0;
  }
  msgECM.dlc = 8;
  setTimer(speedTimer, 100);
}
on message ABS_Wheel_Info
{
  flSpeed = this.ABS_Wheel_FL_Speed;
  frSpeed = this.ABS_Wheel_FR_Speed;
  rlSpeed = this.ABS_Wheel_RL_Speed;
  rrSpeed = this.ABS_Wheel_RR_Speed;
}
on timer speedTimer
{
  // Reset payload before setting signals
  int i;
  for (i = 0; i < 8; i++)
  {
    msgECM.byte(i) = 0;
  }
  msgECM.dlc = 8;
  vehicleSpeed = (flSpeed + frSpeed + rlSpeed + rrSpeed) / 4.0;
  if (vehicleSpeed < 0)   vehicleSpeed = 0;
  if (vehicleSpeed > 260) vehicleSpeed = 260;
  msgECM.ECM_Vehicle_Speed = vehicleSpeed;
  output(msgECM);
  setTimer(speedTimer, 100);
}

/* REQ: ECM-REQ-02 */
variables
{
  msTimer engineSpeedTimer;
  message 520 ECM_Powertrain_Data;
  int engineSpeed = 800;
  int increase = 1;
}
on start
{
  // Initialize message payload to safe state
  int i;
  for (i = 0; i < 8; i++)
  {
    ECM_Powertrain_Data.byte(i) = 0;
  }
  ECM_Powertrain_Data.dlc = 8;
  setTimer(engineSpeedTimer, 100);
}
on timer engineSpeedTimer
{
  // Reset payload before setting signals
  int i;
  for (i = 0; i < 8; i++)
  {
    ECM_Powertrain_Data.byte(i) = 0;
  }
  ECM_Powertrain_Data.dlc = 8;
  if (engineSpeed >= 4000) increase = 0;
  else if (engineSpeed <= 800) increase = 1;
  if (increase) engineSpeed += 100;
  else engineSpeed -= 100;
  ECM_Powertrain_Data.ECM_Engine_Speed = engineSpeed;
  output(ECM_Powertrain_Data);
  setTimer(engineSpeedTimer, 100);
}

/* REQ: ECM-REQ-03 */
variables
{
  msTimer throttleTimer;
  int throttleRaw = 0;
  int direction = 1;
}
on start
{
  setTimer(throttleTimer, 100);
}
on timer throttleTimer
{
  message ECM_Powertrain_Data msg;
  // Reset payload before setting signals
  int i;
  for (i = 0; i < 8; i++)
  {
    msg.byte(i) = 0;
  }
  msg.dlc = 8;
  throttleRaw += direction * 5;
  if (throttleRaw >= 250) { throttleRaw = 250; direction = -1; }
  else if (throttleRaw <= 0) { throttleRaw = 0; direction = 1; }
  msg.ECM_Throttle_Position = throttleRaw;
  output(msg);
  setTimer(throttleTimer, 100);
}

/* REQ: ECM-REQ-04 */
variables
{
  msTimer tempTimer;
  message ECM_Powertrain_Data msgECM;
  int engineTemp = 20;
  int direction = 1;
}
on start
{
  // Initialize message payload to safe state
  int i;
  for (i = 0; i < 8; i++)
  {
    msgECM.byte(i) = 0;
  }
  msgECM.dlc = 8;
  setTimer(tempTimer, 1000);
}
on timer tempTimer
{
  // Reset payload before setting signals
  int i;
  for (i = 0; i < 8; i++)
  {
    msgECM.byte(i) = 0;
  }
  msgECM.dlc = 8;
  engineTemp += direction;
  if (engineTemp >= 110) direction = -1;
  if (engineTemp <= 20) direction = 1;
  msgECM.ECM_Engine_Temp = engineTemp + 40;
  output(msgECM);
  setTimer(tempTimer, 1000);
}

