/* REQ: TCM-REQ-03 */
variables
{
  message 560 TCM_Gear_Status msgTCM;
  msTimer periodicTimer;
  msTimer toggleTimer;
  int clutchState = 0;
}
on start
{
  // Initialize message payload to safe state
  int i;
  for (i = 0; i < 8; i++)
  {
    msgTCM.byte(i) = 0;
  }
  msgTCM.dlc = 8;
  setTimer(periodicTimer, 100);
  setTimer(toggleTimer, 3000);
}
on timer periodicTimer
{
  // Reset payload before setting signals
  int i;
  for (i = 0; i < 8; i++)
  {
    msgTCM.byte(i) = 0;
  }
  msgTCM.dlc = 8;
  msgTCM.TCM_Clutch_Engaged = clutchState;
  msgTCM.TCM_Current_Gear = 1;
  msgTCM.TCM_Shift_In_Progress = 0;
  output(msgTCM);
  setTimer(periodicTimer, 100);
}
on timer toggleTimer
{
  clutchState = !clutchState;
  setTimer(toggleTimer, 3000);
}
